# Standalone harness validating the new chunked NUL-delimited reader logic
# against the old byte-at-a-time reference implementation, across chunk
# boundaries, empty records, and a trailing unterminated record at EOF.

function Invoke-OldReader($bytes) {
    $stream = [System.IO.MemoryStream]::new($bytes)
    $results = [System.Collections.Generic.List[string]]::new()
    while ($true) {
        $acc = [System.Collections.Generic.List[byte]]::new()
        while (($b = $stream.ReadByte()) -notin -1, 0) {
            $acc.Add($b)
        }
        if ($acc.Count -gt 0) {
            $results.Add([Text.Encoding]::UTF8.GetString($acc.ToArray()))
        }
        if ($b -eq -1) {
            return $results
        }
    }
}

function Invoke-NewReader($bytes, $bufferSize) {
    $stream = [System.IO.MemoryStream]::new($bytes)
    $results = [System.Collections.Generic.List[string]]::new()

    $buffer = [byte[]]::new($bufferSize)
    $pending = [System.Collections.Generic.List[byte]]::new()

    $appendSegment = {
        param($segStart, $segEnd)
        $segLen = $segEnd - $segStart
        if ($segLen -le 0) { return }
        $segment = [byte[]]::new($segLen)
        [Array]::Copy($buffer, $segStart, $segment, 0, $segLen)
        $pending.AddRange($segment)
    }

    while ($true) {
        $read = $stream.Read($buffer, 0, $bufferSize)

        if ($read -le 0) {
            if ($pending.Count -gt 0) {
                $results.Add([Text.Encoding]::UTF8.GetString($pending.ToArray()))
            }
            return $results
        }

        $offset = 0
        while ($offset -lt $read) {
            $nul = [Array]::IndexOf($buffer, [byte]0, $offset, $read - $offset)

            if ($nul -lt 0) {
                & $appendSegment $offset $read
                $offset = $read
                continue
            }

            & $appendSegment $offset $nul

            if ($pending.Count -gt 0) {
                $results.Add([Text.Encoding]::UTF8.GetString($pending.ToArray()))
                $pending.Clear()
            }

            $offset = $nul + 1
        }
    }
}

function Build-Bytes([string[]]$records, [bool]$trailingNul, [bool]$trailingPartial) {
    $list = [System.Collections.Generic.List[byte]]::new()
    foreach ($r in $records) {
        $list.AddRange([Text.Encoding]::UTF8.GetBytes($r))
        $list.Add(0)
    }
    if ($trailingPartial) {
        $list.AddRange([Text.Encoding]::UTF8.GetBytes("incomplete-no-terminator"))
    }
    return $list.ToArray()
}

$cases = @(
    @{ name = "simple multi-record"; records = @("hello", "world", "third one here") }
    @{ name = "empty record between two"; records = @("first", "", "third") }
    @{ name = "single large record (1500 bytes)"; records = @(("x" * 1500)) }
    @{ name = "many small records"; records = @(1..50 | ForEach-Object { "rec-$_" }) }
    @{ name = "unicode record"; records = @("café ☃ emoji 😀 done") }
)

$allOk = $true

foreach ($case in $cases) {
    $bytes = Build-Bytes -records $case.records -trailingNul $true -trailingPartial $false
    $old = Invoke-OldReader $bytes
    foreach ($bufSize in @(1, 4, 8, 16, 64, 4096)) {
        $new = Invoke-NewReader $bytes $bufSize
        $match = ($old.Count -eq $new.Count)
        if ($match) {
            for ($i = 0; $i -lt $old.Count; $i++) {
                if ($old[$i] -ne $new[$i]) { $match = $false; break }
            }
        }
        if (-not $match) {
            $allOk = $false
            Write-Output "FAIL [$($case.name)] bufSize=$bufSize"
            Write-Output "  old: $($old -join '|')"
            Write-Output "  new: $($new -join '|')"
        }
    }
}

# trailing unterminated record at EOF (no final NUL)
$bytesPartial = Build-Bytes -records @("first", "second") -trailingNul $true -trailingPartial $true
$oldP = Invoke-OldReader $bytesPartial
foreach ($bufSize in @(1, 4, 16, 4096)) {
    $newP = Invoke-NewReader $bytesPartial $bufSize
    $match = ($oldP.Count -eq $newP.Count)
    if ($match) {
        for ($i = 0; $i -lt $oldP.Count; $i++) {
            if ($oldP[$i] -ne $newP[$i]) { $match = $false; break }
        }
    }
    if (-not $match) {
        $allOk = $false
        Write-Output "FAIL [trailing partial] bufSize=$bufSize"
        Write-Output "  old: $($oldP -join '|')"
        Write-Output "  new: $($newP -join '|')"
    }
}

if ($allOk) {
    Write-Output "ALL CASES MATCH across buffer sizes 1,4,8,16,64,4096"
} else {
    Write-Output "MISMATCHES FOUND"
    exit 1
}

