	"github.com/stretchr/testify/assert"
)

func TestZZTmpFillerParentBackgroundRegression(t *testing.T) {
	env := new(mock.Environment)
	env.On("Shell").Return(shell.GENERIC)

	engine := &Engine{Env: env}

	template.Cache = &cache.Template{
		SimpleTemplate: cache.SimpleTemplate{Shell: shell.GENERIC},
		Segments:       maps.NewConcurrent[any](),
	}
	template.Init(env, nil, nil)

	terminal.Init(shell.GENERIC)
	terminal.Plain = false
	terminal.Colors = &color.Defaults{}
	terminal.ParentColors = nil

	// with blockTailColors set (what captureBlockTailColors would have stored
	// from the block's last segment), the filler's <parentBackground> anchor
	// must resolve to that segment's actual background.
	engine.blockTailColors = &color.Set{Background: "#0000FF", Foreground: "#FFFFFF"}
	withTail, ok := engine.shouldFill("<parentBackground>-</>", 3)
	assert.True(t, ok)
	t.Logf("withTail = %q", withTail)
	assert.True(t, strings.Contains(withTail, "0;0;255"), "expected the blue background escape in %q", withTail)

	// without it (e.g. this is the first block, no previous segment), must not panic
	// and must not fabricate a color.
	terminal.ParentColors = nil
	engine.blockTailColors = nil
	withoutTail, ok := engine.shouldFill("<parentBackground>-</>", 3)
	assert.True(t, ok)
	t.Logf("withoutTail = %q", withoutTail)
	assert.False(t, strings.Contains(withoutTail, "0;0;255"), "should not see the blue background when there is no tail color: %q", withoutTail)
}

